// Config : comptes Meta Ads à scanner.
// Le backfill remonte l'Activity Log sur 2 ans max (Meta garde ~2 ans).

const ORG_ID = '3c68193e-783b-4aa9-bc0d-fb2ce21e99b1';

const accounts = [
  { id: 'act_1147055617398773', name: 'Mayer Energie Clim' },
  { id: 'act_1198344052455745', name: 'Mayer Energie Poêle' },
];

const sinceDate = new Date();
sinceDate.setFullYear(sinceDate.getFullYear() - 2);
const sinceUnix = Math.floor(sinceDate.getTime() / 1000);
const untilUnix = Math.floor(Date.now() / 1000);

return accounts.map((acc) => ({
  json: {
    org_id: ORG_ID,
    ad_account_id: acc.id,
    ad_account_name: acc.name,
    since: sinceUnix,
    until: untilUnix,
  },
}));

// Parse Activity Log Meta → events de budget campagne.
// On garde uniquement les event_type qui modifient le daily_budget campagne.

const accountCtx = $('Loop Accounts').item.json;
const activities = $('Fetch Activity Log').first().json.data || [];

// Event types Meta qui affectent le budget campagne
const RELEVANT_EVENT_TYPES = new Set([
  'update_campaign_budget',
  'update_campaign_duration',
  'create_campaign',
  // Variantes potentielles selon la version API
  'ad_campaign_updated',
]);

const parseExtraData = (raw) => {
  if (!raw) return null;
  if (typeof raw === 'object') return raw;
  try { return JSON.parse(raw); } catch { return null; }
};

const events = [];
for (const act of activities) {
  if (act.object_type !== 'CAMPAIGN') continue;
  if (!RELEVANT_EVENT_TYPES.has(act.event_type)) continue;

  const extra = parseExtraData(act.extra_data) || {};
  // Meta met typiquement { old_value, new_value } ou { daily_budget: { old, new } }
  const newBudget = extra.new_value ?? extra.daily_budget?.new ?? extra.daily_budget ?? null;
  const oldBudget = extra.old_value ?? extra.daily_budget?.old ?? null;

  // Si new_value est absent, on skip (pas un event budget exploitable)
  const newCents = newBudget == null ? null : parseInt(newBudget, 10);
  if (newCents == null || isNaN(newCents) || newCents === 0) continue;

  events.push({
    campaign_id: act.object_id,
    campaign_name: act.object_name,
    event_time: act.event_time,
    event_type: act.event_type,
    new_budget_cents: newCents,
    old_budget_cents: oldBudget == null ? null : (parseInt(oldBudget, 10) || null),
    ad_account_id: accountCtx.ad_account_id,
    translated: act.translated_event_type,
  });
}

return [{ json: { events, ad_account_id: accountCtx.ad_account_id, count: events.length } }];
